1	/**
2	 * Cabinets Details Page Content Component
3	 *
4	 * Handles all state management and data fetching for the cabinet details page.
5	 *
6	 * Features:
7	 * - Cabinet summary and status display
8	 * - SMIB management and configuration
9	 * - Financial metrics and charts
10	 * - Accounting and transaction history
11	 */
12	
13	'use client';
14	
15	import PageLayout from '@/components/shared/layout/PageLayout';
16	import { NoLicenceeAssigned } from '@/components/shared/ui/NoLicenceeAssigned';
17	import { CabinetDetailsLoadingState } from '@/components/shared/ui/skeletons/CabinetDetailSkeletons';
18	
19	import { useCabinetsActionsStore } from '@/lib/store/cabinetActionsStore';
20	import { useDashBoardStore } from '@/lib/store/dashboardStore';
21	import { useUserStore } from '@/lib/store/userStore';
22	import { shouldShowNoLicenceeMessage } from '@/lib/utils/licencee';
23	import CabinetsDeleteCabinetModal from './modals/CabinetsDeleteCabinetModal';
24	import CabinetsEditCabinetModal from './modals/CabinetsEditCabinetModal';
25	
26	// Custom Hooks
27	import { useCabinetPageData } from '@/lib/hooks/cabinets/useCabinetPageData';
28	
29	// Extracted Sections
30	import CabinetsDetailsAccountingSection from '@/components/CMS/cabinets/details/CabinetsDetailsAccountingSection';
31	import CabinetsDetailsChartSection from '@/components/CMS/cabinets/details/CabinetsDetailsChartSection';
32	import CabinetsDetailsSMIBManagementSection from '@/components/CMS/cabinets/details/CabinetsDetailsSMIBManagementSection';
33	import CabinetsDetailsSummarySection from '@/components/CMS/cabinets/details/CabinetsDetailsSummarySection';
34	/**
35	 * Cabinets Details Page Content Component
36	 */
37	export default function CabinetsDetailsPageContent() {
38	  // ============================================================================
39	  // State & Hooks
40	  // ============================================================================
41	  const hook = useCabinetPageData();
42	  const { user } = useUserStore();
43	  const { setSelectedLicencee, selectedLicencee } = useDashBoardStore();
44	  const { openEditModal } = useCabinetsActionsStore();
45	  const {
46	    cabinet,
47	    locationName,
48	    error,
49	    isOnline,
50	    activeTab,
51	    refreshing,
52	    refreshTrigger,
53	    editingSection,
54	    chartData,
55	    loadingChart,
56	    chartGranularity,
57	    activeMetricsFilter,
58	    canAccessSmibConfig,
59	    canEditMachines,
60	    smibHook,
61	    setEditingSection,
62	    setChartGranularity,
63	    handleTabChange,
64	    handleRefresh,
65	    handleCabinetUpdated,
66	    copyToClipboard,
67	    onBack,
68	    onLocationClick,
69	  } = hook;
70	  // TODO Review this component
71	  // ============================================================================
72	  // Early Returns
73	  // ============================================================================
74	  if (shouldShowNoLicenceeMessage(user)) {
75	    return (
76	      <PageLayout
77	        headerProps={{ selectedLicencee, setSelectedLicencee }}
78	        hideOptions
79	        hideLicenceeFilter
80	        mainClassName="flex flex-col flex-1 p-4 md:p-6"
81	      >
82	        <NoLicenceeAssigned />
83	      </PageLayout>
84	    );
85	  }
86	
87	  // Show loading skeleton only for initial load (no cabinet data yet)
88	  // During filter changes, keep showing the existing data with section-level loading indicators
89	  if (!cabinet && !error) {
90	    return (
91	      <CabinetDetailsLoadingState
92	        selectedLicencee={selectedLicencee}
93	        setSelectedLicencee={setSelectedLicencee}
94	        error={error}
95	      />
96	    );
97	  }
98	  if (error || !cabinet) return null; // Error handling handled by hook/page skeleton
99	
100	  return (
101	    <>
102	      <CabinetsEditCabinetModal onCabinetUpdated={handleCabinetUpdated} />
103	      <CabinetsDeleteCabinetModal />
104	
105	      {/* ============================================================================ */}
106	      {/* Render Main Content */}
107	      {/* ============================================================================ */}
108	      <PageLayout
109	        headerProps={{ selectedLicencee, setSelectedLicencee }}
110	        hideOptions
111	        hideLicenceeFilter
112	        mainClassName="flex flex-col flex-1 p-4 md:p-6 overflow-x-hidden"
113	        onRefresh={handleRefresh}
114	        refreshing={refreshing}
115	      >
116	        <div className="flex w-full min-w-0 flex-col gap-6 overflow-hidden">
117	          {/* Header & Summary */}
118	          <CabinetsDetailsSummarySection
119	            cabinet={cabinet}
120	            locationName={locationName}
121	            selectedLicencee={selectedLicencee}
122	            isOnline={isOnline}
123	            refreshing={refreshing}
124	            canEditMachines={canEditMachines}
125	            onBack={onBack}
126	            onRefresh={handleRefresh}
127	            onEdit={() => cabinet && openEditModal(cabinet)}
128	            onCopyToClipboard={copyToClipboard}
129	            onLocationClick={onLocationClick}
130	          />
131	
132	          {/* SMIB Management */}
133	          <CabinetsDetailsSMIBManagementSection
134	            cabinet={cabinet}
135	            canAccessSmibConfig={canAccessSmibConfig}
136	            onRefresh={handleRefresh}
137	            smibConfigExpanded={smibHook.smibConfigExpanded}
138	            mqttConfigData={smibHook.mqttConfigData}
139	            isConnectedToMqtt={smibHook.isConnectedToMqtt}
140	            hasConfigBeenFetched={smibHook.hasConfigBeenFetched}
141	            formData={smibHook.formData}
142	            isManuallyFetching={smibHook.isManuallyFetching}
143	            isEditMode={smibHook.isEditMode}
144	            smibHook={smibHook}
145	            editingSection={editingSection}
146	            onToggleExpand={smibHook.toggleSmibConfig}
147	            onFetchConfig={smibHook.fetchSmibConfiguration}
148	            onResetFormData={smibHook.resetFormData}
149	            onSaveAll={async () => {
150	              const relayId = cabinet.relayId || cabinet.smibBoard;
151	              if (!relayId) return;
152	              await smibHook.saveConfiguration(cabinet._id);
153	            }}
154	            onSaveConfig={async cmd => {
155	              const relayId = cabinet.relayId || cabinet.smibBoard;
156	              if (!relayId) return;
157	
158	              // Handle machine control commands
159	              if (cmd) {
160	                const success = await smibHook.saveConfiguration(
161	                  cabinet._id,
162	                  cmd
163	                );
164	                if (success) {
165	                  const { toast } = await import('sonner');
166	                  toast.success(
167	                    `Machine control command "${cmd}" sent successfully!`
168	                  );
169	                }
170	                return;
171	              }
172	
173	              // Handle section-based configuration updates
174	              const { toast } = await import('sonner');
175	
176	              if (editingSection === 'network') {
177	                try {
178	                  const networkData = {
179	                    netStaSSID:
180	                      smibHook.formData.networkSSID !== 'No Value Provided'
181	                        ? smibHook.formData.networkSSID
182	                        : undefined,
183	                    netStaPwd:
184	                      smibHook.formData.networkPassword !== 'No Value Provided'
185	                        ? smibHook.formData.networkPassword
186	                        : undefined,
187	                    netStaChan:
188	                      smibHook.formData.networkChannel !== 'No Value Provided'
189	                        ? parseInt(smibHook.formData.networkChannel)
190	                        : undefined,
191	                  };
192	
193	                  // If SMIB is online, send MQTT command
194	                  if (smibHook.isConnectedToMqtt) {
195	                    await smibHook.updateNetworkConfig(relayId, networkData);
196	                  }
197	
198	                  // Always update database
199	                  await fetch('/api/mqtt/update-machine-config', {
