242	        } catch (clipboardError) {
243	          console.warn(
244	            'Clipboard API failed, trying fallback:',
245	            clipboardError
246	          );
247	          // Fall through to fallback
248	        }
249	      }
250	
251	      // 2. Fallback for older browsers or non-secure contexts
252	      const textArea = document.createElement('textarea');
253	      textArea.value = cleanText;
254	
255	      // Ensure the textarea is off-screen but still part of the DOM
256	      textArea.style.position = 'fixed';
257	      textArea.style.left = '-9999px';
258	      textArea.style.top = '0';
259	      textArea.style.opacity = '0';
260	      document.body.appendChild(textArea);
261	
262	      textArea.focus();
263	      textArea.select();
264	
265	      let successful = false;
266	      try {
267	        successful = document.execCommand('copy');
268	      } catch (err) {
269	        console.error('execCommand copy failed:', err);
270	      }
271	
272	      document.body.removeChild(textArea);
273	
274	      if (successful) {
275	        toast.success(`${label} copied to clipboard`);
276	      } else {
277	        throw new Error('Copy command failed');
278	      }
279	    } catch (err) {
280	      console.error(`Failed to copy ${label}:`, err);
