63	  const makePollingRequest = useAbortableRequest();
64	
65	  // ============================================================================
66	  // Data Fetching
67	  // ============================================================================
68	
69	  const fetchCabinetDetailsData = useCallback(async () => {
70	    setError(null);
71	    setErrorType('unknown');
72	    setMetricsLoading(true);
73	
74	    let wasAborted = false;
75	
76	    try {
77	      // Read latest values from store at call time to avoid stale closures
78	      // (e.g. when called via onCustomRangeGo setTimeout callback)
79	      const storeState = useDashBoardStore.getState();
80	      const currentActiveMetricsFilter =
81	        storeState.activeMetricsFilter || activeMetricsFilter;
82	      const currentCustomDateRange =
83	        storeState.customDateRange || customDateRange;
84	
85	      // Fetch cabinet data with current date filter - no default fallback
86	      if (!currentActiveMetricsFilter) {
87	        setMetricsLoading(false);
88	        return;
89	      }
90	
91	      // Robustly check for custom dates - support both {from, to} and {startDate, endDate}
92	      const hasCustomDates =
93	        currentActiveMetricsFilter === 'Custom' &&
94	        ((currentCustomDateRange?.startDate &&
95	          currentCustomDateRange?.endDate) ||
96	          (currentCustomDateRange?.from && currentCustomDateRange?.to) ||
97	          (currentCustomDateRange?.start && currentCustomDateRange?.end));
98	
99	      if (currentActiveMetricsFilter === 'Custom' && !hasCustomDates) {
100	        setMetricsLoading(false);
101	        return;
102	      }
103	
104	      // Resolve effective custom ranges into a standard { from, to } Date format
105	      const from =
106	        currentCustomDateRange?.startDate ||
107	        currentCustomDateRange?.from ||
108	        currentCustomDateRange?.start;
109	      const to =
110	        currentCustomDateRange?.endDate ||
111	        currentCustomDateRange?.to ||
112	        currentCustomDateRange?.end;
113	
114	      const effectiveRange =
115	        currentActiveMetricsFilter === 'Custom' && from && to
116	          ? {
117	              from: from instanceof Date ? from : new Date(String(from)),
118	              to: to instanceof Date ? to : new Date(String(to)),
119	            }
120	          : undefined;
121	
122	      // Always pass current display currency so cabinet detail values
123	      // are returned in the header-selected currency.
124	      const cabinetData = await makeRequest(signal =>
125	        fetchCabinetById(
126	          slug,
127	          currentActiveMetricsFilter,
128	          effectiveRange,
129	          displayCurrency,
130	          selectedLicencee || null,
131	          signal
132	        )
133	      );
134	
135	      // NOTE: reviewer multiplier is applied server-side — no client-side scaling needed
136	
137	      // If request was aborted (returned null), keep existing cabinet data
138	      if (cabinetData === null || cabinetData === undefined) {
139	        wasAborted = true;
140	        return;
141	      }
142	
143	      setCabinet(cabinetData);
144	
145	      // Use location name directly from cabinet data
146	      if (cabinetData?.locationName) {
147	        setLocationName(cabinetData.locationName);
148	      } else if (cabinetData?.locationId) {
149	        setLocationName('Location Not Found');
150	      } else {
151	        setLocationName('No Location Assigned');
152	      }
153	
154	      // WOW machines have no SMIB/relay but are always treated as online.
155	      if (isWowMachine(cabinetData)) {
156	        setIsOnline(true);
157	      } else if ((cabinetData as Record<string, unknown>)?.aceEnabled === true) {
158	        setIsOnline(true);
159	      } else if (cabinetData?.lastActivity) {
160	        const lastActive = new Date(cabinetData.lastActivity);
161	        setIsOnline(differenceInMinutes(new Date(), lastActive) <= 3);
162	      }
163	    } catch (err) {
164	      // Silently handle aborted requests - keep existing data, don't set error
165	      if (isAbortError(err)) {
166	        wasAborted = true;
167	        return;
168	      }
169	
170	      setCabinet(null);
171	
172	      // Determine error type based on the error
173	      if (err instanceof Error) {
174	        // Check for unauthorized access (403)
175	        const errorWithStatus = err as Error & {
176	          status?: number;
177	          isUnauthorized?: boolean;
178	          response?: { status?: number };
179	        };
180	        if (
181	          errorWithStatus.status === 403 ||
182	          errorWithStatus.isUnauthorized ||
183	          errorWithStatus.response?.status === 403 ||
184	          err.message.includes('Unauthorized') ||
185	          err.message.includes('do not have access')
186	        ) {
187	          setError('You are not authorized to view this cabinet');
188	          setErrorType('unauthorized');
189	        } else if (
190	          err.message.includes('404') ||
191	          err.message.includes('not found')
192	        ) {
193	          setError('Cabinet not found');
194	          setErrorType('not-found');
195	        } else if (
196	          err.message.includes('network') ||
197	          err.message.includes('fetch')
198	        ) {
199	          setError('Network error');
200	          setErrorType('network');
201	        } else {
202	          setError('Failed to fetch cabinet details');
203	          setErrorType('unknown');
204	        }
205	      } else {
206	        setError('Failed to fetch cabinet details');
207	        setErrorType('unknown');
208	      }
209	
210	      // Only show toast for non-unauthorized errors
211	      const errorWithStatus =
212	        err instanceof Error
213	          ? (err as Error & {
214	              status?: number;
215	              isUnauthorized?: boolean;
216	              response?: { status?: number };
217	            })
218	          : null;
219	      const isUnauthorized =
220	        errorWithStatus &&
221	        (errorWithStatus.status === 403 ||
222	          errorWithStatus.isUnauthorized ||
223	          errorWithStatus.response?.status === 403 ||
224	          errorWithStatus.message.includes('Unauthorized') ||
225	          errorWithStatus.message.includes('do not have access'));
226	
227	      if (!isUnauthorized) {
228	        toast.error('Failed to fetch cabinet details');
229	      }
230	    } finally {
231	      // Don't clear loading on abort — a new request is in-flight and will clear it
232	      if (!wasAborted) {
233	        setMetricsLoading(false);
234	      }
235	    }
236	  }, [
237	    slug,
238	    activeMetricsFilter,
239	    customDateRange,
240	    selectedLicencee,
241	    displayCurrency,
242	    makeRequest,
243	    // Include specific date values to ensure reference changes are caught
244	    customDateRange?.startDate?.getTime(),
245	    customDateRange?.endDate?.getTime(),
246	    customDateRange?.from?.getTime(),
247	    customDateRange?.to?.getTime(),
248	  ]);
249	
250	  // Callback function to refresh cabinet data after updates
251	  const handleCabinetUpdated = useCallback(() => {
252	    fetchCabinetDetailsData();
253	  }, [fetchCabinetDetailsData]);
254	
255	  // Silent background poll — updates cabinet state without touching metricsLoading.
256	  // Uses a separate makePollingRequest so it never aborts the main fetch.
257	  const fetchCabinetDetailsSilent = useCallback(async () => {
258	    try {
259	      const storeState = useDashBoardStore.getState();
260	      const currentActiveMetricsFilter =
261	        storeState.activeMetricsFilter || activeMetricsFilter;
262	      const currentCustomDateRange =
263	        storeState.customDateRange || customDateRange;
264	
265	      if (!currentActiveMetricsFilter) return;
266	
267	      const hasCustomDates =
268	        currentActiveMetricsFilter === 'Custom' &&
269	        ((currentCustomDateRange?.startDate &&
270	          currentCustomDateRange?.endDate) ||
271	          (currentCustomDateRange?.from && currentCustomDateRange?.to) ||
272	          (currentCustomDateRange?.start && currentCustomDateRange?.end));
273	
274	      if (currentActiveMetricsFilter === 'Custom' && !hasCustomDates) return;
275	
276	      const from =
277	        currentCustomDateRange?.startDate ||
278	        currentCustomDateRange?.from ||
279	        currentCustomDateRange?.start;
280	      const to =
281	        currentCustomDateRange?.endDate ||
282	        currentCustomDateRange?.to ||
283	        currentCustomDateRange?.end;
284	
285	      const effectiveRange =
286	        currentActiveMetricsFilter === 'Custom' && from && to
287	          ? {
288	              from: from instanceof Date ? from : new Date(String(from)),
289	              to: to instanceof Date ? to : new Date(String(to)),
290	            }
291	          : undefined;
292	
293	      const cabinetData = await makePollingRequest(signal =>
294	        fetchCabinetById(
295	          slug,
296	          currentActiveMetricsFilter,
297	          effectiveRange,
298	          displayCurrency,
299	          selectedLicencee || null,
300	          signal
301	        )
302	      );
303	
304	      if (!cabinetData) return;
305	
306	      setCabinet(cabinetData);
307	
308	      if (cabinetData?.locationName) {
309	        setLocationName(cabinetData.locationName);
310	      }
311	
312	      // WOW machines have no SMIB/relay but are always treated as online.
313	      if (isWowMachine(cabinetData)) {
314	        setIsOnline(true);
315	      } else if ((cabinetData as Record<string, unknown>)?.aceEnabled === true) {
316	        setIsOnline(true);
317	      } else if (cabinetData?.lastActivity) {
318	        const lastActive = new Date(cabinetData.lastActivity);
319	        setIsOnline(differenceInMinutes(new Date(), lastActive) <= 3);
320	      }
321	    } catch (err) {
322	      if (isAbortError(err)) return;
323	      // Silently ignore polling errors — don't update error state or show toasts
324	    }
325	  }, [
326	    slug,
327	    activeMetricsFilter,
328	    customDateRange,
329	    selectedLicencee,
330	    displayCurrency,
331	    makePollingRequest,
332	    customDateRange?.startDate?.getTime(),
333	    customDateRange?.endDate?.getTime(),
334	    customDateRange?.from?.getTime(),
335	    customDateRange?.to?.getTime(),
336	  ]);
337	
338	  // ============================================================================
339	  // Effects
340	  // ============================================================================
341	
342	  useEffect(() => {
343	    // Only fetch if we have a valid date filter and it's been properly initialized
344	    if (activeMetricsFilter && dateFilterInitialized) {
345	      fetchCabinetDetailsData();
346	    }
347	  }, [
348	    slug,
349	    activeMetricsFilter,
350	    dateFilterInitialized,
351	    customDateRange,
352	    displayCurrency,
353	    selectedLicencee,
354	    fetchCabinetDetailsData,
355	    // Force trigger on date value changes
356	    customDateRange?.startDate?.getTime(),
357	    customDateRange?.endDate?.getTime(),
358	    customDateRange?.from?.getTime(),
359	    customDateRange?.to?.getTime(),
360	  ]);
361	
362	  return {
363	    cabinet,
364	    locationName,
365	    error,
366	    errorType,
367	    metricsLoading,
368	    isOnline,
369	    fetchCabinetDetailsData,
370	    fetchCabinetDetailsSilent,
371	    handleCabinetUpdated,
372	  };
373	}
