179	/**
180	 * POST handler - Create new cabinet
181	 *
182	 * Flow:
183	 * 1. Parse and validate request body
184	 * 2. Create cabinet (dedup check, build doc, save, log activity)
185	 * 3. Return created cabinet
186	 */
187	export async function POST(request: NextRequest) {
188	  const startTime = Date.now();
189	  const user = extractUserFromRequest(request);
190	
191	  return withApiAuth(request, async () => {
192	    try {
193	      // ============================================================================
194	      // STEP 1: Parse Body and Validate
195	      // ============================================================================
196	      const data = (await request.json()) as MachinePayload;
197	      if (!data.gamingLocation && data.locationId)
198	        data.gamingLocation = data.locationId;
199	
200	      if (!data.gamingLocation) {
201	        logRouteError(
202	          functionName,
203	          'POST',
204	          '/api/cabinets',
205	          'Location required',
206	          user
207	        );
