209	          { success: false, error: 'Location required' },
210	          { status: 400 }
211	        );
212	      }
213	
214	      // ============================================================================
215	      // STEP 2: Create Cabinet
216	      // ============================================================================
217	      const result = await createCabinet(data);
218	
219	      if (!result.success) {
220	        logRouteError(
221	          functionName,
222	          'POST',
223	          '/api/cabinets',
