246	      );
247	    } catch (error) {
248	      const errorMessage =
249	        error instanceof Error ? error.message : 'Failed to create cabinet';
250	      logRouteError(
251	        functionName,
252	        'POST',
253	        '/api/cabinets',
254	        errorMessage,
255	        user
256	      );
257	      return NextResponse.json(
258	        { success: false, error: errorMessage },
259	        { status: 500 }
260	      );
261	    }
262	  });
263	}
