63	/**
64	 * Main GET handler for Cabinet Aggregation
65	 *
66	 * @param {string} locationId - Comma-separated location IDs to filter by
67	 * @param {string} gameType - Comma-separated game types to filter by
68	 * @param {string} search - Search query for serial, name, or SMIB
69	 * @param {string} licencee - Filter machines by licencee name
70	 * @param {string} timePeriod - Time range preset ('Today', 'Yesterday', '7d', '30d', 'Custom', 'LastHour')
