82	 * 1. Parse query parameters
83	 * 2. Validate timePeriod parameter
84	 * 3. Get user's accessible licencees and permissions
85	 * 4. Technician restriction
86	 * 5. Fetch locations with gameDayOffset
87	 * 6. Calculate gaming day ranges per location
88	 * 7. Aggregate machine metrics (optimized for 30d/7d vs Today/Yesterday)
89	 * 8. Refine offline status
90	 * 9. Apply currency conversion if needed
91	 * 10. Apply reviewer scale
92	 * 11. Sort and paginate
93	 * 12. Return aggregated machine data
94	 */
95	export async function GET(req: NextRequest) {
96	  return withApiAuth(
97	    req,
98	    async ({ user: userPayload, userRoles, isAdminOrDev }) => {
