120	        startDateParam,
121	        endDateParam,
122	        debug,
123	      } = params;
124	
125	      // ============================================================================
126	      // STEP 2: Validate timePeriod parameter
127	      // ============================================================================
128	      if (!timePeriod) {
129	        logRouteError(
130	          functionName,
131	          'GET',
132	          '/api/cabinets/aggregation',
133	          'timePeriod parameter is required',
134	          user
135	        );
