137	          { error: 'timePeriod parameter is required' },
138	          { status: 400 }
139	        );
140	      }
141	
142	      // ============================================================================
143	      // STEP 3: Get user's accessible licencees and permissions
144	      // ============================================================================
145	      const userAccessibleLicencees =
146	        await getUserAccessibleLicenceesFromToken();
147	      let userLocationPermissions: string[] = [];
148	      if (
149	        Array.isArray(
150	          (userPayload as { assignedLocations?: string[] })?.assignedLocations
151	        )
152	      ) {
153	        userLocationPermissions = (
154	          userPayload as { assignedLocations: string[] }
155	        ).assignedLocations;
156	      }
157	
158	      let allowedLocationIds = await getUserLocationFilter(
159	        userAccessibleLicencees,
160	        licencee || undefined,
