162	        userRoles
163	      );
164	
165	      const isAdmin = userRoles
166	        .map(r => r?.toLowerCase?.() ?? r)
167	        .some(r => r === 'admin' || r === 'developer' || r === 'owner');
168	      if (isAdmin && locationIdArray.length > 0) {
