177	      );
178	      const isOnlyTechnician =
179	        userRolesLower.includes('technician') &&
180	        !userRolesLower.some(r =>
181	          ['admin', 'developer', 'manager', 'location admin', 'owner'].includes(
182	            r
183	          )
