331	        const allLocationMachines =
332	          await Machine.find(machineMatchQuery).lean<GamingMachine[]>();
333	
334	        if (allLocationMachines.length > 0) {
335	          const machineToLocation = new Map<string, string>();
336	          allLocationMachines.forEach(machine => {
337	            machineToLocation.set(String(machine._id), machine.gamingLocation ? String(machine.gamingLocation) : '');
338	          });
