408	          });
409	        }
410	      } else {
411	        // Batch processing for Today/Yesterday/Custom/LastHour
412	        const BATCH_SIZE = 20;
413	        for (
414	          let locationIndex = 0;
415	          locationIndex < locations.length;
416	          locationIndex += BATCH_SIZE
417	        ) {
418	          const batch = locations.slice(locationIndex, locationIndex + BATCH_SIZE);
419	          const batchLocationIds = batch
420	            .map(loc => String(loc._id))
421	            .filter(id => gamingDayRanges.has(id));
422	
423	          if (batchLocationIds.length === 0) continue;
424	
425	          const batchMachineMatchQuery = buildMachineMatchQuery(
426	            batchLocationIds,
427	            deletedFilter,
428	            { searchTerm, selectedGameTypes, onlineStatus, smibStatus },
429	            batch
430	          );
431	
432	          const batchAllMachines = await Machine.find(
433	            batchMachineMatchQuery
434	          ).lean<GamingMachine[]>();
435	
436	          if (batchAllMachines.length === 0) continue;
437	
438	          const batchMachinesByLocation = new Map<string, GamingMachine[]>();
439	          batchAllMachines.forEach(machine => {
440	            const locationId = machine.gamingLocation ? String(machine.gamingLocation) : null;
441	            if (locationId && batchLocationIds.includes(locationId)) {
442	              if (!batchMachinesByLocation.has(locationId)) {
443	                batchMachinesByLocation.set(locationId, []);
444	              }
445	              batchMachinesByLocation.get(locationId)?.push(machine);
446	            }
447	          });
448	
449	          let batchGlobalStart = new Date();
450	          let batchGlobalEnd = new Date(0);
451	          batchLocationIds.forEach(locId => {
452	            const range = gamingDayRanges.get(locId);
453	            if (range) {
454	              if (range.rangeStart < batchGlobalStart) batchGlobalStart = range.rangeStart;
455	              if (range.rangeEnd > batchGlobalEnd) batchGlobalEnd = range.rangeEnd;
456	            }
457	          });
458	
459	          const allBatchMachineIds = batchAllMachines.map(m => String(m._id));
460	          const machineToLocationMap = new Map<string, string>();
461	          batchAllMachines.forEach(machine => {
462	            const machineId = String(machine._id);
463	            const locId = machine.gamingLocation ? String(machine.gamingLocation) : null;
464	            if (locId) machineToLocationMap.set(machineId, locId);
465	          });
466	
467	          const batchMetersPipeline = buildBatchMetersPipeline(
468	            allBatchMachineIds,
469	            batchGlobalStart,
470	            batchGlobalEnd,
471	            timePeriod
472	          );
473	
474	          const batchMetricsAggregation = await Meters.aggregate(
475	            batchMetersPipeline,
476	            { maxTimeMS: 90000 }
477	          ).exec();
478	
479	          const metricsByMachine = new Map<string, MachineMetrics>();
480	          batchMetricsAggregation.forEach(agg => {
481	            const machineId = String(agg._id);
482	            const locationId = machineToLocationMap.get(machineId);
483	            const gameDayRange = locationId ? gamingDayRanges.get(locationId) : undefined;
484	            const aggRecord = agg as Record<string, unknown>;
485	
486	            if (!gameDayRange || timePeriod === 'All Time') {
487	              metricsByMachine.set(machineId, {
488	                moneyIn: (aggRecord.moneyIn as number) || 0,
489	                moneyOut: (aggRecord.moneyOut as number) || 0,
490	                jackpot: (aggRecord.jackpot as number) || 0,
491	                coinIn: (aggRecord.coinIn as number) || 0,
492	                coinOut: (aggRecord.coinOut as number) || 0,
