496	                meterCount: (aggRecord.meterCount as number) || 0,
497	              });
498	            } else {
499	              const minReadAt = new Date(aggRecord.minReadAt as Date);
500	              const maxReadAt = new Date(aggRecord.maxReadAt as Date);
501	              const hasValidReadAt =
502	                (minReadAt >= gameDayRange.rangeStart && minReadAt <= gameDayRange.rangeEnd) ||
503	                (maxReadAt >= gameDayRange.rangeStart && maxReadAt <= gameDayRange.rangeEnd) ||
504	                (minReadAt <= gameDayRange.rangeStart && maxReadAt >= gameDayRange.rangeEnd);
505	
506	              if (hasValidReadAt) {
507	                const existing = metricsByMachine.get(machineId);
508	                const newMetrics: MachineMetrics = {
509	                  moneyIn: (aggRecord.moneyIn as number) || 0,
510	                  moneyOut: (aggRecord.moneyOut as number) || 0,
511	                  jackpot: (aggRecord.jackpot as number) || 0,
512	                  coinIn: (aggRecord.coinIn as number) || 0,
513	                  coinOut: (aggRecord.coinOut as number) || 0,
514	                  gamesPlayed: (aggRecord.gamesPlayed as number) || 0,
515	                  gamesWon: (aggRecord.gamesWon as number) || 0,
516	                  handPaidCancelledCredits: (aggRecord.handPaidCancelledCredits as number) || 0,
517	                  meterCount: (aggRecord.meterCount as number) || 0,
518	                };
519	
520	                if (existing) {
