531	
532	          const batchLocationMap = new Map<string, LocationDocument>();
533	          batch.forEach(loc => {
534	            batchLocationMap.set(String(loc._id), loc);
535	          });
536	
537	          batch.forEach(location => {
538	            const locationIdStr = String(location._id);
539	            const locationMachines = batchMachinesByLocation.get(locationIdStr) || [];
540	            if (locationMachines.length === 0) return;
541	
542	            locationMachines.forEach(machine => {
543	              const machineId = String(machine._id);
544	              const metrics = metricsByMachine.get(machineId) || getDefaultMetrics();
