546	                buildMachineResponse(machine, metrics, location, licenceeIncludeJackpotMap, timePeriod)
547	              );
548	            });
549	          });
550	        }
551	      }
552	
553	      // ============================================================================
554	      // STEP 8: Refine offline status and apply filtering
555	      // ============================================================================
556	      allMachines = refineOfflineStatus(allMachines, onlineStatus, timePeriod, gamingDayRanges);
557	
558	      let filteredMachines = allMachines;
559	
560	      // ============================================================================
561	      // STEP 9: Apply currency conversion if needed
562	      // ============================================================================
563	      if (isAdminOrDev && shouldApplyCurrencyConversion(licencee)) {
564	        const db = await connectDB();
565	        if (!db) {
566	          return NextResponse.json({ error: 'DB connection failed' }, { status: 500 });
567	        }
568	
569	        const licenceesData = await Licencee.find(
570	          {
571	            $or: [
572	              { deletedAt: null },
573	              { deletedAt: { $lt: new Date('2025-01-01') } },
574	            ],
575	          },
576	          { _id: 1, name: 1, includeJackpot: 1 }
577	        ).lean<LicenceeDocument[]>();
