583	          licenceeIdToIncludeJackpot.set(String(lic._id), Boolean(lic.includeJackpot));
584	        });
585	
586	        const { getCountryCurrency, getLicenceeCurrency, convertToUSD } =
587	          await import('@/lib/helpers/rates');
588	        const countriesData = await Countries.find({}).lean<CountryDocument[]>();
589	        const countryIdToName = new Map<string, string>();
590	        countriesData.forEach(country => {
591	          if (country._id && country.name) {
592	            countryIdToName.set(String(country._id), country.name);
593	          }
594	        });
595	
596	        const locationDetailsMap = new Map<string, LocationDocument>();
597	        for (const location of locations) {
