661	          return {
662	            ...machine,
663	            moneyIn,
664	            moneyOut,
665	            cancelledCredits: roundTwo(convertFromUSD(cancelledCreditsUSD, displayCurrency)),
666	            jackpot,
667	            gross,
668	            netGross,
669	            coinIn: roundTwo(convertFromUSD(coinInUSD, displayCurrency)),
670	            coinOut: roundTwo(convertFromUSD(coinOutUSD, displayCurrency)),
671	            includeJackpot,
672	          };
673	        });
674	      }
675	
676	      // ============================================================================
677	      // STEP 10: Apply reviewer multiplier
678	      // ============================================================================
679	      const scaleReferenceDate = customEndDateForGamingDay ?? new Date();
680	      const moneyInScale = getMoneyInScale(
681	        userPayload as {
682	          moneyInMultiplier?: number | null;
683	          roles?: string[];
684	          reviewerMultiplierStartTime?: Date | string | null;
685	        },
686	        scaleReferenceDate
687	      );
688	      const moneyOutScale = getMoneyOutAndJackpotScale(
689	        userPayload as {
690	          moneyOutAndJackpotMultiplier?: number | null;
691	          roles?: string[];
692	          reviewerMultiplierStartTime?: Date | string | null;
693	        },
694	        scaleReferenceDate
695	      );
696	      filteredMachines = applyReviewerScale(filteredMachines, moneyInScale, moneyOutScale);
697	
698	      // ============================================================================
699	      // STEP 11: Sort and paginate
700	      // ============================================================================
701	      const sortBy = searchParams.get('sortBy') || 'moneyIn';
702	      const sortOrderRaw = searchParams.get('sortOrder') || 'desc';
703	      const sortOrder = sortOrderRaw.toLowerCase() === 'asc' ? 1 : -1;
704	
705	      sortCabinetMachines(filteredMachines, searchTerm, sortBy, sortOrder);
706	
707	      const totalCount = filteredMachines.length;
708	      let paginatedMachines = filteredMachines;
709	
710	      if (limit) {
711	        const skip = (page - 1) * limit;
712	        paginatedMachines = filteredMachines.slice(skip, skip + limit);
713	      }
714	
715	      // ============================================================================
716	      // STEP 12: Return aggregated machine data
717	      // ============================================================================
718	      type DebugInfo = {
719	        userAccessibleLicencees: string[] | 'all';
720	        userRoles: string[];
721	        userLocationPermissions: string[];
722	        licenceeParam: string | null;
723	        allowedLocationIds: string | string[];
724	        locationsFound: number;
725	        locationSample: Array<{ id: string; name: string; licencee?: string }>;
726	        machinesReturned: number;
727	        totalMachines?: number;
728	        timePeriod: string;
729	      };
730	
731	      type ApiResponse = {
732	        success: boolean;
733	        data: typeof paginatedMachines;
734	        pagination?: {
735	          page: number;
736	          limit: number;
737	          total: number;
738	          totalPages: number;
739	        };
740	        debug?: DebugInfo;
741	      };
742	
743	      const response: ApiResponse = {
744	        success: true,
745	        data: paginatedMachines,
746	      };
747	
748	      if (limit) {
749	        response.pagination = {
750	          page,
751	          limit,
752	          total: totalCount,
753	          totalPages: Math.ceil(totalCount / limit),
754	        };
755	      }
756	
757	      if (debug) {
758	        response.debug = {
759	          userAccessibleLicencees,
760	          userRoles,
761	          userLocationPermissions,
762	          licenceeParam: licencee,
763	          allowedLocationIds:
764	            allowedLocationIds === 'all'
765	              ? 'ALL'
766	              : (allowedLocationIds as string[])?.slice(0, 10),
767	          locationsFound: locations.length,
768	          locationSample: locations.slice(0, 3).map(l => ({
769	            id: String(l._id),
770	            name: String(l.name),
771	            licencee: l.rel?.licencee ? String(l.rel.licencee) : undefined,
772	          })),
773	          machinesReturned: paginatedMachines.length,
774	          totalMachines: totalCount,
775	          timePeriod,
776	        };
777	      }
778	
779	      const duration = Date.now() - startTime;
780	      if (duration > 1000) {
781	        console.warn(`[Cabinet Aggregation API] Completed in ${duration}ms`);
782	      }
783	      logRouteFetch(
784	        functionName,
785	        'GET',
786	        '/api/cabinets/aggregation',
787	        paginatedMachines.length,
788	        user,
789	        duration
790	      );
791	
792	      return NextResponse.json(response);
793	    }
794	  );
795	}
