76	      if (!machine) {
77	        logRouteError(
78	          functionName,
79	          'GET',
80	          '/api/cabinets/[cabinetId]',
81	          `Not found: ${cabinetId}`,
82	          user
83	        );
84	        return NextResponse.json(
85	          { success: false, error: 'Cabinet not found' },
86	          { status: 404 }
87	        );
88	      }
89	
90	      const locationId = String(machine.gamingLocation);
91	      if (!locationId) {
92	        logRouteError(
93	          functionName,
94	          'GET',
95	          '/api/cabinets/[cabinetId]',
