97	          user
98	        );
99	        return NextResponse.json(
100	          { success: false, error: 'Cabinet has no associated location' },
101	          { status: 400 }
102	        );
103	      }
104	
105	      const hasAccess = await checkUserLocationAccess(locationId);
106	      if (!hasAccess) {
107	        logRouteError(
108	          functionName,
109	          'GET',
110	          '/api/cabinets/[cabinetId]',
