112	          user
113	        );
114	        return NextResponse.json(
115	          { success: false, error: 'Unauthorized: Access denied' },
116	          { status: 403 }
117	        );
118	      }
119	
120	      // ============================================================================
121	      // STEP 2: Fetch Location & Licencee Settings
122	      // ============================================================================
123	      const {
124	        location,
