145	          reviewerMultiplierStartTime?: Date | string | null;
146	        },
147	        dateField
148	      );
149	
150	      // ============================================================================
151	      // STEP 4: Apply Currency Conversion
152	      // ============================================================================
153	      const convertedMetrics = await convertCabinetCurrency(
154	        metrics,
155	        displayCurrency,
156	        userRoles,
157	        licenceeId,
158	        location
159	      );
160	
161	      // ============================================================================
162	      // STEP 5: Transform and Return
163	      // ============================================================================
164	      const transformed = buildCabinetResponse(
165	        machine,
166	        convertedMetrics,
167	        location?.name || 'Unknown Location',
168	        aceEnabled,
169	        includeJackpot
170	      );
171	
172	      const duration = Date.now() - startTime;
173	      logRouteFetch(
174	        functionName,
175	        'GET',
176	        '/api/cabinets/[cabinetId]',
177	        1,
178	        user,
179	        duration
180	      );
181	      return NextResponse.json({ success: true, data: transformed });
182	    } catch (e) {
183	      const errorMessage = e instanceof Error ? e.message : 'Unknown error';
184	      logRouteError(
185	        functionName,
186	        'GET',
187	        '/api/cabinets/[cabinetId]',
188	        errorMessage,
189	        user
190	      );
191	      console.error('[GET /cabinets/[cabinetId]] Error:', errorMessage);
192	      return NextResponse.json(
193	        { success: false, error: 'Internal Server Error' },
194	        { status: 500 }
195	      );
196	    }
197	  });
198	}
