151	  const limitParam = searchParams.get('limit');
152	  const page = pageParam ? Math.max(1, parseInt(pageParam, 10)) : 1;
153	  const limit = limitParam
154	    ? Math.max(1, parseInt(limitParam, 10))
155	    : undefined;
156	
157	  const startDateParam = searchParams.get('startDate');
158	  const endDateParam = searchParams.get('endDate');
159	  const debug = searchParams.get('debug') === 'true';
160	
161	  return {
162	    locationIdArray,
163	    selectedGameTypes,
164	    searchTerm,
165	    licencee,
166	    timePeriod,
167	    displayCurrency,
168	    onlineStatus,
169	    smibStatus,
170	    membership,
171	    page,
172	    limit,
173	    startDateParam,
174	    endDateParam,
175	    debug,
176	  };
177	}
