183	/**
184	 * Builds the MongoDB match query for filtering machines.
185	 * Eliminates duplication between the 7d/30d and batch processing branches.
186	 *
187	 * @param {string[]} locationIds - Location IDs to filter by
188	 * @param {Record<string, unknown>} deletedFilter - Soft-delete filter
189	 * @param {CabinetAggregationParams} params - Parsed query parameters
190	 * @param {LocationDocument[]} locations - Fetched locations for aceEnabled check
191	 * @returns {Record<string, unknown>} The MongoDB match query
192	 */
193	export function buildMachineMatchQuery(
194	  locationIds: string[],
195	  deletedFilter: Record<string, unknown>,
196	  params: Pick<CabinetAggregationParams, 'searchTerm' | 'selectedGameTypes' | 'onlineStatus' | 'smibStatus'>,
197	  locations: LocationDocument[]
198	): Record<string, unknown> {
199	  const machineMatchQuery: Record<string, unknown> = {
200	    gamingLocation: { $in: locationIds },
201	    $and: [deletedFilter] as Array<Record<string, unknown>>,
202	  };
203	
204	  const andArray = machineMatchQuery.$and as Array<Record<string, unknown>>;
205	
206	  if (params.searchTerm) {
207	    const searchRegex = { $regex: params.searchTerm, $options: 'i' };
208	    andArray.push({
209	      $or: [
210	        { serialNumber: searchRegex },
211	        { 'custom.name': searchRegex },
212	        { 'Custom.name': searchRegex },
213	        { relayId: searchRegex },
214	        { smibBoard: searchRegex },
215	        { _id: searchRegex },
216	      ],
217	    });
218	  }
219	
220	  if (params.selectedGameTypes.length > 0) {
221	    andArray.push({
222	      $or: [
223	        { game: { $in: params.selectedGameTypes } },
224	        {
225	          $and: [
226	            { $or: [{ game: null }, { game: '' }] },
227	            { gameType: { $in: params.selectedGameTypes } },
228	          ],
229	        },
230	      ],
231	    });
232	  }
233	
234	  if (params.onlineStatus !== 'all') {
235	    const threeMinutesAgo = new Date(Date.now() - 3 * 60 * 1000);
236	    const aceEnabledLocIds = locations
237	      .filter(loc => loc.aceEnabled === true)
238	      .map(loc => String(loc._id));
239	
240	    if (params.onlineStatus === 'online') {
241	      andArray.push({
242	        $or: [
243	          { relayId: { $exists: true, $nin: [null, ''] } },
244	          { 'meta.dataSync.source': 'wow' },
245	        ],
246	      });
247	      const onlineConds: Array<Record<string, unknown>> = [
248	        { lastActivity: { $gte: threeMinutesAgo } },
249	        { 'meta.dataSync.source': 'wow' },
250	      ];
251	      if (aceEnabledLocIds.length > 0) {
252	        onlineConds.push({ gamingLocation: { $in: aceEnabledLocIds } });
253	      }
254	      andArray.push({ $or: onlineConds });
255	    } else if (params.onlineStatus === 'offline') {
256	      andArray.push({ 'meta.dataSync.source': { $ne: 'wow' } });
257	      andArray.push({ relayId: { $exists: true, $nin: [null, ''] } });
258	      andArray.push({
259	        $or: [
260	          { lastActivity: { $lt: threeMinutesAgo } },
261	          { lastActivity: { $exists: false } },
262	          { lastActivity: null },
263	        ],
264	      });
265	      if (aceEnabledLocIds.length > 0) {
266	        andArray.push({ gamingLocation: { $nin: aceEnabledLocIds } });
267	      }
268	    } else if (params.onlineStatus === 'never-online') {
269	      andArray.push({ 'meta.dataSync.source': { $ne: 'wow' } });
270	      andArray.push({ relayId: { $exists: true, $nin: [null, ''] } });
271	      andArray.push({
272	        $or: [
273	          { lastActivity: { $exists: false } },
274	          { lastActivity: null },
275	        ],
276	      });
277	      if (aceEnabledLocIds.length > 0) {
278	        andArray.push({ gamingLocation: { $nin: aceEnabledLocIds } });
279	      }
280	    }
281	  }
282	
283	  if (params.smibStatus !== 'all') {
284	    if (params.smibStatus === 'smib') {
285	      andArray.push({
286	        $or: [
287	          { relayId: { $ne: '', $exists: true, $not: /^\s*$/ } },
288	          { smibBoard: { $ne: '', $exists: true, $not: /^\s*$/ } },
289	          { 'meta.dataSync.source': 'wow' },
290	        ],
291	      });
292	    } else if (params.smibStatus === 'no-smib') {
293	      andArray.push({
294	        $and: [
295	          { 'meta.dataSync.source': { $ne: 'wow' } },
296	          {
297	            $or: [
298	              { relayId: '' },
299	              { relayId: null },
300	              { relayId: { $exists: false } },
301	              { relayId: /^\s*$/ },
302	            ],
303	          },
304	          {
305	            $or: [
306	              { smibBoard: '' },
307	              { smibBoard: null },
308	              { smibBoard: { $exists: false } },
309	              { smibBoard: /^\s*$/ },
310	            ],
311	          },
312	        ],
313	      });
314	    }
315	  }
316	
317	  return machineMatchQuery;
318	}
