324	/**
325	 * Builds a standardized machine response object from a GamingMachine,
326	 * its metrics, and location data. Eliminates duplication between branches.
327	 *
328	 * @param {GamingMachine} machine - The machine document
329	 * @param {MachineMetrics} metrics - Aggregated meter metrics
330	 * @param {LocationDocument} location - The machine's gaming location
331	 * @param {Map<string, boolean>} licenceeIncludeJackpotMap - Licencee jackpot settings
332	 * @param {string} timePeriod - Current time period for context
333	 * @returns {CabinetMachineResponse} Formatted machine response
334	 */
335	export function buildMachineResponse(
336	  machine: GamingMachine,
337	  metrics: MachineMetrics,
338	  location: LocationDocument,
339	  licenceeIncludeJackpotMap: Map<string, boolean>,
340	  timePeriod: string
341	): CabinetMachineResponse {
342	  const machineId = String(machine._id);
343	  const locationId = String(location._id);
344	
345	  const licenceeId = Array.isArray(location.rel?.licencee)
346	    ? location.rel.licencee[0]
347	    : location.rel?.licencee;
348	  const includeJackpot = licenceeId
349	    ? licenceeIncludeJackpotMap.get(String(licenceeId)) || false
350	    : false;
351	
352	  const moneyIn = metrics.moneyIn || 0;
353	  const rawMoneyOut = metrics.moneyOut || 0;
354	  const jackpot = metrics.jackpot || 0;
355	  const moneyOut = rawMoneyOut + (includeJackpot ? jackpot : 0);
356	  const gross = moneyIn - moneyOut;
357	  const netGross = moneyIn - rawMoneyOut - jackpot;
358	
359	  const serialNumber = String(machine.serialNumber || '').trim();
360	  const customName = String(
361	    (machine.custom as Record<string, unknown>)?.name ||
362	      (machine as Record<string, unknown>).Custom ||
363	      ''
364	  ).trim();
365	  const finalSerialNumber = serialNumber || customName || '';
366	
367	  const threeMinutesAgo = new Date(Date.now() - 3 * 60 * 1000);
368	  const hasRelayId = !!(
369	    machine.relayId && String(machine.relayId).trim().length > 0
370	  );
371	  // WOW machines have no SMIB/relay but are always treated as online.
372	  const isWow = isWowMachine(machine);
373	  const isOnline =
374	    isWow ||
375	    (hasRelayId &&
376	      (location.aceEnabled === true ||
377	        (machine.lastActivity
378	          ? new Date(machine.lastActivity as Date) > threeMinutesAgo
379	          : false)));
380	
381	  return {
382	    _id: machineId,
383	    locationId,
384	    locationName: (location.name as string) || '(No Location)',
385	    assetNumber: finalSerialNumber,
386	    serialNumber: finalSerialNumber,
387	    custom: (machine.custom || {}) as Record<string, unknown>,
388	    game: String(machine.game || machine.gameType || ''),
389	    installedGame: String(machine.game || machine.gameType || ''),
390	    denomination: String(machine.denomination || ''),
391	    manufacturer: String(machine.manufacturer || ''),
392	    model: String(machine.model || ''),
393	    status: machine.assetStatus || machine.machineStatus || 'unknown',
394	    isSasMachine: machine.isSasMachine || false,
395	    aceEnabled: location.aceEnabled === true,
396	    relayId: machine.relayId || '',
397	    smibBoard: machine.smibBoard || '',
398	    smbId: machine.relayId || machine.smibBoard || '',
399	    cabinetType: machine.cabinetType || '',
400	    assetStatus: machine.assetStatus || machine.machineStatus || '',
401	    accountingDenomination: String(
402	      machine.gameConfig?.accountingDenomination || '1'
403	    ),
404	    collectorDenomination: machine.collectorDenomination || 1,
405	    collectionMultiplier: String(machine.collectorDenomination || 1),
406	    isCronosMachine: false,
407	    createdAt: machine.createdAt as Date | undefined,
408	    updatedAt: machine.updatedAt as Date | undefined,
409	    deletedAt: machine.deletedAt as Date | undefined,
410	    lastOnline: (machine.lastActivity as Date | undefined) || null,
411	    lastActivity: (machine.lastActivity as Date | undefined) || null,
412	    online: isOnline,
413	    moneyIn,
414	    moneyOut,
415	    cancelledCredits: rawMoneyOut,
416	    gross,
417	    netGross,
418	    jackpot,
419	    coinIn: metrics.coinIn || 0,
420	    coinOut: metrics.coinOut || 0,
421	    gamesPlayed: metrics.gamesPlayed || 0,
422	    gamesWon: metrics.gamesWon || 0,
423	    includeJackpot,
424	    handPaidCancelledCredits: metrics.handPaidCancelledCredits || 0,
425	    meterCount: metrics.meterCount || 0,
426	    rel: location.rel,
427	    country: location.country,
428	    timePeriod,
429	    meta: machine.meta,
430	  };
431	}
