434	// Meters Aggregation Pipeline Builder
435	// ============================================================================
436	
437	/**
438	 * Builds the Meters aggregation pipeline for per-location metrics.
439	 *
440	 * @param {string[]} machineIds - Machine IDs to aggregate
441	 * @param {{ rangeStart: Date; rangeEnd: Date }} gameDayRange - Gaming day range
442	 * @returns {PipelineStage[]} The aggregation pipeline
443	 */
444	export function buildPerLocationMetersPipeline(
445	  machineIds: string[],
446	  gameDayRange: { rangeStart: Date; rangeEnd: Date }
447	): PipelineStage[] {
448	  return [
449	    {
450	      $match: {
451	        machine: { $in: machineIds },
452	        readAt: {
453	          $gte: gameDayRange.rangeStart,
454	          $lte: gameDayRange.rangeEnd,
455	        },
456	      },
457	    },
458	    {
459	      $project: {
460	        machine: 1,
461	        drop: '$movement.drop',
462	        totalCancelledCredits: '$movement.totalCancelledCredits',
463	        jackpot: '$movement.jackpot',
464	        coinIn: 1,
465	        coinOut: 1,
466	        gamesPlayed: 1,
467	        gamesWon: 1,
468	        handPaidCancelledCredits: 1,
469	      },
470	    },
471	    {
472	      $group: {
473	        _id: '$machine',
474	        moneyIn: { $sum: '$drop' },
475	        moneyOut: { $sum: '$totalCancelledCredits' },
476	        jackpot: { $sum: '$jackpot' },
477	        coinIn: { $last: '$coinIn' },
478	        coinOut: { $last: '$coinOut' },
479	        gamesPlayed: { $last: '$gamesPlayed' },
480	        gamesWon: { $last: '$gamesWon' },
481	        handPaidCancelledCredits: { $last: '$handPaidCancelledCredits' },
482	        meterCount: { $sum: 1 },
483	      },
484	    },
485	  ];
486	}
487	
488	/**
489	 * Builds the Meters aggregation pipeline for batch processing.
490	 *
491	 * @param {string[]} machineIds - Machine IDs to aggregate
492	 * @param {Date} globalStart - Earliest gaming day start across locations
493	 * @param {Date} globalEnd - Latest gaming day end across locations
494	 * @param {string} timePeriod - Current time period
495	 * @returns {PipelineStage[]} The aggregation pipeline
496	 */
497	export function buildBatchMetersPipeline(
498	  machineIds: string[],
499	  globalStart: Date,
500	  globalEnd: Date,
501	  timePeriod: string
502	): PipelineStage[] {
503	  return [
504	    {
505	      $match: {
506	        machine: { $in: machineIds },
507	        ...(timePeriod !== 'All Time'
508	          ? { readAt: { $gte: globalStart, $lte: globalEnd } }
509	          : {}),
510	      },
511	    },
512	    {
513	      $group: {
514	        _id: '$machine',
515	        moneyIn: { $sum: { $ifNull: ['$movement.drop', 0] } },
516	        moneyOut: { $sum: { $ifNull: ['$movement.totalCancelledCredits', 0] } },
517	        jackpot: { $sum: { $ifNull: ['$movement.jackpot', 0] } },
518	        coinIn: { $last: '$coinIn' },
519	        coinOut: { $last: '$coinOut' },
520	        gamesPlayed: { $last: '$gamesPlayed' },
521	        gamesWon: { $last: '$gamesWon' },
522	        handPaidCancelledCredits: { $last: '$handPaidCancelledCredits' },
523	        meterCount: { $sum: 1 },
524	        minReadAt: { $min: '$readAt' },
525	        maxReadAt: { $max: '$readAt' },
526	      },
527	    },
528	  ];
529	}
