554	// ============================================================================
555	// Offline Status Refinement
556	// ============================================================================
557	
558	/**
559	 * Refines offline status for all machines and applies offline filtering.
560	 * Calculates offline time labels and applies period-aware filtering.
561	 *
562	 * @param {CabinetMachineResponse[]} machines - Machine response array
563	 * @param {string} onlineStatus - Requested online status filter
564	 * @param {string} timePeriod - Current time period
565	 * @param {Map<string, { rangeStart: Date; rangeEnd: Date }>} gamingDayRanges - Per-location gaming day ranges
566	 * @returns {CabinetMachineResponse[]} Filtered and annotated machines
567	 */
568	export function refineOfflineStatus(
569	  machines: CabinetMachineResponse[],
570	  onlineStatus: string,
571	  timePeriod: string,
572	  gamingDayRanges: Map<string, { rangeStart: Date; rangeEnd: Date }>
573	): CabinetMachineResponse[] {
574	  const threeMinutesAgo = new Date(Date.now() - 3 * 60 * 1000);
575	
576	  let refinedMachines = machines.map(machine => {
577	    const lastActivity = machine.lastActivity
578	      ? new Date(machine.lastActivity)
579	      : null;
580	    const aceEnabled = machine.aceEnabled === true;
581	    // WOW machines have no SMIB/relay but are always treated as online.
582	    const isOnline =
583	      isWowMachine(machine) ||
584	      aceEnabled ||
585	      (lastActivity && lastActivity > threeMinutesAgo);
586	
587	    let offlineTimeLabel: string | undefined = undefined;
588	    let actualOfflineTime: string | undefined = undefined;
589	
590	    if (!isOnline && lastActivity) {
591	      const actualDuration = formatDistanceToNow(lastActivity, {
592	        addSuffix: true,
593	      });
594	      actualOfflineTime = actualDuration;
595	      offlineTimeLabel = actualDuration;
596	    } else if (!isOnline && !lastActivity) {
597	      actualOfflineTime = 'Never';
598	      offlineTimeLabel = 'Never';
599	    }
600	
601	    return {
602	      ...machine,
603	      online: !!isOnline,
604	      offlineTimeLabel,
605	      actualOfflineTime,
606	    };
607	  });
608	
609	  if (onlineStatus.startsWith('offline')) {
610	    refinedMachines = refinedMachines.filter(machine => {
611	      const lastActivity = machine.lastActivity
612	        ? new Date(machine.lastActivity)
613	        : null;
614	      const aceEnabled = machine.aceEnabled === true;
615	      const isOnline =
616	        isWowMachine(machine) ||
617	        aceEnabled ||
618	        (lastActivity && lastActivity > threeMinutesAgo);
619	      machine.online = !!isOnline;
620	
621	      if (isOnline) return false;
622	
623	      const range = gamingDayRanges.get(String(machine.locationId));
624	      if (!range) return true;
625	
626	      if (timePeriod === 'Today' || timePeriod === 'Yesterday') {
627	        if (!lastActivity) return false;
628	        return (
629	          lastActivity >= range.rangeStart && lastActivity <= range.rangeEnd
630	        );
631	      } else {
632	        return !lastActivity || lastActivity <= range.rangeEnd;
633	      }
634	    });
635	  }
636	
637	  return refinedMachines;
638	}
