641	// Reviewer Scale Application
642	// ============================================================================
643	
644	/**
645	 * Applies reviewer multiplier to financial values for all machines.
646	 *
647	 * @param {CabinetMachineResponse[]} machines - Machine response array
648	 * @param {number} moneyInScale - Scale factor for money in
649	 * @param {number} moneyOutScale - Scale factor for money out and jackpot
650	 * @returns {CabinetMachineResponse[]} Scaled machines
651	 */
652	export function applyReviewerScale(
653	  machines: CabinetMachineResponse[],
654	  moneyInScale: number,
655	  moneyOutScale: number
656	): CabinetMachineResponse[] {
657	  if (moneyInScale === 1 && moneyOutScale === 1) return machines;
658	
659	  return machines.map(machine => {
660	    const scaledMoneyIn = machine.moneyIn * moneyInScale;
661	    const scaledMoneyOut = machine.moneyOut * moneyOutScale;
662	    const scaledJackpot = machine.jackpot * moneyOutScale;
663	    const scaledCancelledCredits = machine.cancelledCredits * moneyOutScale;
664	    return {
665	      ...machine,
666	      moneyIn: scaledMoneyIn,
667	      moneyOut: scaledMoneyOut,
668	      jackpot: scaledJackpot,
669	      cancelledCredits: scaledCancelledCredits,
670	      gross: scaledMoneyIn - scaledMoneyOut,
671	      netGross: scaledMoneyIn - scaledCancelledCredits - scaledJackpot,
672	    };
673	  });
674	}
