676	// ============================================================================
677	// Machine Sorting
678	// ============================================================================
679	
680	/**
681	 * Sorts cabinet machines by search relevance, online priority, and configurable field.
682	 *
683	 * @param {CabinetMachineResponse[]} machines - Machines to sort (mutated in place)
684	 * @param {string} searchTerm - Current search term for relevance sorting
685	 * @param {string} sortBy - Field to sort by
686	 * @param {number} sortOrder - 1 for ascending, -1 for descending
687	 */
688	export function sortCabinetMachines(
689	  machines: CabinetMachineResponse[],
690	  searchTerm: string,
691	  sortBy: string,
692	  sortOrder: number
693	): void {
694	  machines.sort((a, b) => {
695	    if (searchTerm) {
696	      const searchLower = searchTerm.toLowerCase();
697	      const aSerial = String(a.serialNumber || '').toLowerCase();
698	      const bSerial = String(b.serialNumber || '').toLowerCase();
699	      const aName = String(
700	        (a.custom as { name?: string })?.name || ''
701	      ).toLowerCase();
702	      const bName = String(
703	        (b.custom as { name?: string })?.name || ''
704	      ).toLowerCase();
705	
706	      const aStarts =
707	        aSerial.startsWith(searchLower) || aName.startsWith(searchLower);
708	      const bStarts =
709	        bSerial.startsWith(searchLower) || bName.startsWith(searchLower);
710	
711	      if (aStarts && !bStarts) return -1;
712	      if (!aStarts && bStarts) return 1;
713	    }
714	
715	    const aOnline = a.online === true;
716	    const bOnline = b.online === true;
717	
718	    if (sortBy === 'offlineTime') {
719	      if (aOnline && !bOnline) return -1;
720	      if (!aOnline && bOnline) return 1;
721	      if (aOnline && bOnline) return 0;
722	
723	      const aTime = a.lastActivity
724	        ? new Date(a.lastActivity).getTime()
725	        : 0;
726	      const bTime = b.lastActivity
727	        ? new Date(b.lastActivity).getTime()
728	        : 0;
729	
730	      if (aTime === 0 && bTime > 0) return 1;
731	      if (aTime > 0 && bTime === 0) return -1;
732	      if (aTime === 0 && bTime === 0) return 0;
733	
734	      return (aTime < bTime ? 1 : -1) * sortOrder;
735	    }
736	
737	    if (aOnline && !bOnline) return -1;
738	    if (!aOnline && bOnline) return 1;
739	
740	    const valA = (a as Record<string, unknown>)[sortBy];
741	    const valB = (b as Record<string, unknown>)[sortBy];
742	
743	    const safeA = valA === undefined || valA === null ? 0 : valA;
744	    const safeB = valB === undefined || valB === null ? 0 : valB;
745	
746	    if (typeof safeA === 'string' && typeof safeB === 'string') {
747	      return sortOrder === 1
748	        ? safeA.localeCompare(safeB)
749	        : safeB.localeCompare(safeA);
750	    }
751	
752	    const numA = Number(safeA);
753	    const numB = Number(safeB);
754	
755	    if (!isNaN(numA) && !isNaN(numB)) {
756	      return sortOrder === 1 ? numA - numB : numB - numA;
757	    }
758	
759	    return 0;
760	  });
761	}
