767	/**
768	 * Builds location data for gaming day range calculation.
769	 *
770	 * @param {LocationDocument[]} locations - Fetched locations
771	 * @param {Map<string, boolean>} licenceeIncludeJackpotMap - Licencee jackpot settings
772	 * @returns {LocationWithRange[]} Location data with offset and jackpot settings
773	 */
774	export function buildLocationRangeInputs(
775	  locations: LocationDocument[],
776	  licenceeIncludeJackpotMap: Map<string, boolean>
777	): LocationWithRange[] {
778	  return locations.map(loc => {
779	    const locRecord = loc as unknown as Record<string, unknown>;
780	    const rel = locRecord.rel as Record<string, unknown> | undefined;
781	    const licenceeId = Array.isArray(rel?.licencee)
782	      ? (rel?.licencee as string[])[0]
783	      : (rel?.licencee as string | undefined);
784	    return {
785	      _id: String(locRecord._id),
786	      gameDayOffset: (locRecord.gameDayOffset as number) ?? 8,
787	      includeJackpot: licenceeId
788	        ? licenceeIncludeJackpotMap.get(String(licenceeId)) || false
789	        : false,
790	    };
791	  });
792	}
