116	  const copyToClipboard = async (text: string, label: string) => {
117	    if (!text || text.trim() === '' || text === 'N/A') {
118	      toast.error(`No ${label} value to copy`);
119	      return;
120	    }
121	    try {
122	      await navigator.clipboard.writeText(text.trim());
123	      toast.success(`${label} copied to clipboard`);
124	    } catch {
125	      // Fallback for older browsers or when clipboard API is not available
126	      try {
127	        const textArea = document.createElement('textarea');
128	        textArea.value = text.trim();
129	        textArea.style.position = 'fixed';
130	        textArea.style.left = '-999999px';
131	        textArea.style.top = '-999999px';
132	        document.body.appendChild(textArea);
133	        textArea.focus();
134	        textArea.select();
135	        const successful = document.execCommand('copy');
136	        document.body.removeChild(textArea);
137	        if (successful) {
138	          toast.success(`${label} copied to clipboard`);
139	        } else {
140	          throw new Error('execCommand failed');
141	        }
142	      } catch (fallbackError) {
143	        console.error('Failed to copy to clipboard:', fallbackError);
144	        toast.error(`Failed to copy ${label}. Please try again.`);
